// MARK: - Validation Errors

enum UniversalLinkError: Error, CustomStringConvertible {
    case invalidURL
    case untrustedHost(String)
    case unrecognizedPath(String)
    case missingRequiredParameter(String)
    case invalidParameterFormat(parameter: String, reason: String)
    case rateLimitExceeded
    case authorizationRequired
    case tokenExpired
    case tokenValidationFailed
    case schemeNotAllowed(String)
    
    var description: String {
        switch self {
        case .invalidURL:
            return "The URL could not be parsed."
        case .untrustedHost(let host):
            return "Host '\(host)' is not in the allowlist."
        case .unrecognizedPath(let path):
            return "Path '\(path)' is not a recognized route."
        case .missingRequiredParameter(let param):
            return "Required parameter '\(param)' is missing."
        case .invalidParameterFormat(let param, let reason):
            return "Parameter '\(param)' is invalid: \(reason)"
        case .rateLimitExceeded:
            return "Too many link attempts. Please wait before trying again."
        case .authorizationRequired:
            return "You must be signed in to access this screen."
        case .tokenExpired:
            return "This reset link has expired. Please request a new one."
        case .tokenValidationFailed:
            return "The reset token could not be validated."
        case .schemeNotAllowed(let scheme):
            return "URL scheme '\(scheme)' is not allowed."
        }
    }
}

// MARK: - Rate Limiter

final class LinkRateLimiter {
    static let shared = LinkRateLimiter()
    
    private var attempts: [TimeInterval] = []
    private let lock = NSLock()
    
    private init() {}
    
    func checkRateLimit() -> Bool {
        lock.lock()
        defer { lock.unlock() }
        
        let now = Date().timeIntervalSince1970
        let windowStart = now - 60.0
        
        // Remove attempts outside the window
        attempts.removeAll { $0 < windowStart }
        
        guard attempts.count < UniversalLinkConfig.maxLinkAttemptsPerMinute else {
            return false
        }
        
        attempts.append(now)
        return true
    }
    
    func reset() {
        lock.lock()
        defer { lock.unlock() }
        attempts.removeAll()
    }
}

// MARK: - Token Validator

struct TokenValidator {
    
    /// Validates token format locally before sending to server.
    /// This is a preliminary check — the server performs the authoritative validation.
    static func validateTokenFormat(_ token: String) -> Result<String, UniversalLinkError> {
        // Check length bounds
        guard token.count >= UniversalLinkConfig.tokenMinLength else {
            return .failure(.invalidParameterFormat(
                parameter: "token",
                reason: "Token is too short (minimum \(UniversalLinkConfig.tokenMinLength) characters)."
            ))
        }
        
        guard token.count <= UniversalLinkConfig.tokenMaxLength else {
            return .failure(.invalidParameterFormat(
                parameter: "token",
                reason: "Token exceeds maximum length (\(UniversalLinkConfig.tokenMaxLength) characters)."
            ))
        }
        
        // Check allowed characters only
        let tokenCharacterSet = CharacterSet(charactersIn: token)
        guard tokenCharacterSet.isSubset(of: UniversalLinkConfig.tokenAllowedCharacters) else {
            return .failure(.invalidParameterFormat(
                parameter: "token",
                reason: "Token contains invalid characters."
            ))
        }
        
        // Check for path traversal or injection attempts
        guard !token.contains(".."),
              !token.contains("/"),
              !token.contains("\\"),
              !token.contains("%") else {
            return .failure(.invalidParameterFormat(
                parameter: "token",
                reason: "Token contains disallowed sequences."
            ))
        }
        
        return .success(token)
    }
    
    /// Validates email format if provided
    static func validateEmailFormat(_ email: String) -> Result<String, UniversalLinkError> {
        let normalized = email.lowercased().trimmingCharacters(in: .whitespacesAndNewlines)
        
        guard normalized.count <= 254 else {
            return .failure(.invalidParameterFormat(
                parameter: "email",
                reason: "Email exceeds maximum length."
            ))
        }
        
        // Basic email format validation
        let emailRegex = #"^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$"#
        guard normalized.range(of: emailRegex, options: .regularExpression) != nil else {
            return .failure(.invalidParameterFormat(
                parameter: "email",
                reason: "Invalid email format."
            ))
        }
        
        return .success(normalized)
    }
}

