// MARK: - Universal Link Parser

final class UniversalLinkParser {
    
    /// Parses and validates a universal link URL.
    /// Returns a validated ParsedUniversalLink or throws a descriptive error.
    static func parse(_ url: URL) -> Result<ParsedUniversalLink, UniversalLinkError> {
        
        // 1. Validate scheme — only HTTPS allowed for universal links
        guard let scheme = url.scheme?.lowercased(), scheme == "https" else {
            let scheme = url.scheme ?? "nil"
            return .failure(.schemeNotAllowed(scheme))
        }
        
        // 2. Validate host against allowlist
        guard let host = url.host?.lowercased(),
              UniversalLinkConfig.allowedHosts.contains(host) else {
            let host = url.host ?? "nil"
            return .failure(.untrustedHost(host))
        }
        
        // 3. Normalize and validate path
        let path = normalizePath(url.path)
        
        guard let routeConfig = UniversalLinkConfig.allowedRoutes[path] else {
            return .failure(.unrecognizedPath(path))
        }
        
        // 4. Parse query parameters
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return .failure(.invalidURL)
        }
        
        let queryItems = components.queryItems ?? []
        var validatedParams: [String: String] = [:]
        
        // Build a dictionary of raw query params (take first occurrence only to prevent parameter pollution)
        var rawParams: [String: String] = [:]
        for item in queryItems {
            if rawParams[item.name] == nil {
                rawParams[item.name] = item.value
            }
        }
        
        // 5. Check all required parameters are present
        for requiredParam in routeConfig.requiredParams {
            guard let value = rawParams[requiredParam], !value.isEmpty else {
                return .failure(.missingRequiredParameter(requiredParam))
            }
        }
        
        // 6. Validate each known parameter
        let allKnownParams = Set(routeConfig.requiredParams + routeConfig.optionalParams)
        
        for (key, value) in rawParams {
            // Ignore unknown parameters — do not pass them through
            guard allKnownParams.contains(key) else {
                continue
            }
            
            guard let value = value, !value.isEmpty else {
                continue
            }
            
            // Validate based on parameter name
            switch key {
            case "token":
                switch TokenValidator.validateTokenFormat(value) {
                case .success(let validToken):
                    validatedParams[key] = validToken
                case .failure(let error):
                    return .failure(error)
                }
                
            case "email":
                switch TokenValidator.validateEmailFormat(value) {
                case .success(let validEmail):
                    validatedParams[key] = validEmail
                case .failure(let error):
                    return .failure(error)
                }
                
            default:
                // Generic sanitization for any other allowed parameter
                let sanitized = sanitizeParameter(value)
                guard sanitized.count <= 512 else {
                    return .failure(.invalidParameterFormat(
                        parameter: key,
                        reason: "Parameter value exceeds maximum length."
                    ))
                }
                validatedParams[key] = sanitized
            }
        }
        
        let parsed = ParsedUniversalLink(
            destination: routeConfig.destination,
            parameters: validatedParams,
            requiresAuth: routeConfig.requiresAuth
        )
        
        return .success(parsed)
    }
    
    /// Normalizes a URL path to prevent path traversal and canonicalization attacks
    private static func normalizePath(_ path: String) -> String {
        var normalized = path.lowercased()
        
        // Remove trailing slash (but keep root "/")
        if normalized.count > 1 && normalized.hasSuffix("/") {
            normalized = String(normalized.dropLast())
        }
        
        // Resolve any ".." or "." components
        let components = normalized.split(separator: "/").filter { $0 != "." && $0 != ".." }
        normalized = "/" + components.joined(separator: "/")
        
        return normalized
    }
    
    /// Basic parameter sanitization
    private static func sanitizeParameter(_ value: String) -> String {
        // Remove null bytes and control characters
        return value.unicodeScalars
            .filter { !$0.properties.isDefaultIgnorableCodePoint && $0.value >= 0x20 }
            .map { String($0) }
            .joined()
    }
}

