// MARK: - Universal Link Handler

final class UniversalLinkHandler {
    
    private let authService: AuthenticationServiceProtocol
    private let tokenService: TokenValidationServiceProtocol
    private weak var navigator: NavigationCoordinatorProtocol?
    private let rateLimiter: LinkRateLimiter
    
    init(
        authService: AuthenticationServiceProtocol,
        tokenService: TokenValidationServiceProtocol,
        navigator: NavigationCoordinatorProtocol,
        rateLimiter: LinkRateLimiter = .shared
    ) {
        self.authService = authService
        self.tokenService = tokenService
        self.navigator = navigator
        self.rateLimiter = rateLimiter
    }
    
    /// Main entry point for handling universal links.
    /// Call this from SceneDelegate or AppDelegate when a universal link is received.
    func handleUniversalLink(_ url: URL) {
        
        // 1. Rate limiting check
        guard rateLimiter.checkRateLimit() else {
            logSecurityEvent("Rate limit exceeded for universal link", url: url)
            navigator?.showError(.rateLimitExceeded)
            return
        }
        
        // 2. Parse and validate the URL
        let parseResult = UniversalLinkParser.parse(url)
        
        switch parseResult {
        case .failure(let error):
            logSecurityEvent("Universal link validation failed: \(error)", url: url)
            navigator?.showError(error)
            return
            
        case .success(let parsedLink):
            // 3. Authorization check for protected routes
            if parsedLink.requiresAuth && !authService.isUserAuthenticated {
                logSecurityEvent("Unauthorized access attempt to protected route", url: url)
                navigator?.showError(.authorizationRequired)
                return
            }
            
            // 4. Route to the appropriate destination
            routeToDestination(parsedLink, originalURL: url)
        }
    }
    
    private func routeToDestination(_ link: ParsedUniversalLink, originalURL: URL) {
        switch link.destination {
        case .passwordReset:
            handlePasswordReset(link, originalURL: originalURL)
            
        case .emailVerification:
            handleEmailVerification(link)
            
        case .accountSettings:
            handleAccountSettings()
        }
    }
    
    // MARK: - Password Reset Flow
    
    private func handlePasswordReset(_ link: ParsedUniversalLink, originalURL: URL) {
        guard let token = link.parameters["token"] else {
            navigator?.showError(.missingRequiredParameter("token"))
            return
        }
        
        let email = link.parameters["email"] // Optional
        
        // Show loading while we validate the token server-side
        navigator?.showLoading(true)
        
        // Server-side token validation — the authoritative check
        tokenService.validateResetToken(token) { [weak self] result in
            DispatchQueue.main.async {
                self?.navigator?.showLoading(false)
                
                switch result {
                case .success(let isValid):
                    if isValid {
                        self?.logEvent("Navigating to password reset screen")
                        self?.navigator?.navigateToPasswordReset(token: token, email: email)
                    } else {
                        self?.logSecurityEvent("Token validation failed (expired or invalid)", url: originalURL)
                        self?.navigator?.showError(.tokenExpired)
                    }
                    
                case .failure:
                    self?.logSecurityEvent("Token validation service error", url: originalURL)
                    self?.navigator?.showError(.tokenValidationFailed)
                }
            }
        }
    }
    
    // MARK: - Email Verification Flow
    
    private func handleEmailVerification(_ link: ParsedUniversalLink) {
        guard let token = link.parameters["token"] else {
            navigator?.showError(.missingRequiredParameter("token"))
            return
        }
        
        navigator?.navigateToEmailVerification(token: token)
    }
    
    // MARK: - Account Settings Flow
    
    private func handleAccountSettings() {
        // requiresAuth is already checked before routing
        navigator?.navigateToAccountSettings()
    }
    
    // MARK: - Logging
    
    private func logSecurityEvent(_ message: String, url: URL) {
        // In production, send to your security monitoring/SIEM system
        // Redact sensitive parameters from logs
        let sanitizedURL = redactSensitiveParams(from: url)
        print("[SECURITY] \(message) | URL: \(sanitizedURL)")
    }
    
    private func logEvent(_ message: String) {
        print("[UniversalLink] \(message)")
    }
    
    private func redactSensitiveParams(from url: URL) -> String {
        guard var components = URLComponents(url: url, resolvingAgainstBaseURL: false) else {
            return "[invalid URL]"
        }
        
        let sensitiveParams: Set<String> = ["token", "email"]
        components.queryItems = components.queryItems?.map { item in
            if sensitiveParams.contains(item.name) {
                return URLQueryItem(name: item.name, value: "[REDACTED]")
            }
            return item
        }
        
        return components.string ?? "[invalid URL]"
    }
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    private var universalLinkHandler: UniversalLinkHandler?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        let rootVC = MainViewController()
        let navController = UINavigationController(rootViewController: rootVC)
        window.rootViewController = navController
        self.window = window
        window.makeKeyAndVisible()
        
        // Initialize the handler
        setupUniversalLinkHandler(navigator: rootVC)
        
        // Handle universal links from cold launch
        if let urlContext = connectionOptions.urlContexts.first {
            handleIncomingURL(urlContext.url)
        }
        
        if let userActivity = connectionOptions.userActivities.first,
           userActivity.activityType == NSUserActivityTypeBrowsingWeb,
           let url = userActivity.webpageURL {
            handleIncomingURL(url)
        }
    }
    
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        handleIncomingURL(url)
    }
    
    func scene(_ scene: UIScene, openURLContexts URLContexts: Set<UIOpenURLContext>) {
        // Note: Universal links come through `continue userActivity`, not here.
        // This handles custom URL schemes if needed.
    }
    
    private func setupUniversalLinkHandler(navigator: NavigationCoordinatorProtocol) {
        let authService = AppAuthenticationService()
        let tokenService = AppTokenValidationService()
        
        universalLinkHandler = UniversalLinkHandler(
            authService: authService,
            tokenService: tokenService,
            navigator: navigator
        )
    }
    
    private func handleIncomingURL(_ url: URL) {
        universalLinkHandler?.handleUniversalLink(url)
    }
}

