final class AppTokenValidationService: TokenValidationServiceProtocol {
    
    func validateResetToken(_ token: String, completion: @escaping (Result<Bool, Error>) -> Void) {
        // Make a server-side API call to validate the token
        // The server should check:
        // - Token exists in the database
        // - Token has not expired
        // - Token has not been used already
        // - Token is associated with a valid user account
        
        guard let url = URL(string: "https://api.myapp.com/auth/validate-reset-token") else {
            completion(.failure(NSError(domain: "TokenValidation", code: -1)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.timeoutInterval = 15
        
        let body: [String: String] = ["token": token]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        // Pin to expected certificate in production (use URLSessionDelegate for cert pinning)
        let session = URLSession.shared
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(NSError(domain: "TokenValidation", code: -2)))
                return
            }
            
            switch httpResponse.statusCode {
            case 200:
                // Token is valid
                completion(.success(true))
            case 410:
                // Token expired
                completion(.success(false))
            case 404:
                // Token not found
                completion(.success(false))
            default:
                completion(.failure(NSError(
                    domain: "TokenValidation",
                    code: httpResponse.statusCode,
                    userInfo: [NSLocalizedDescriptionKey: "Unexpected server response"]
                )))
            }
        }
        task.resume()
    }
}

