        print("Navigate to account settings")
    }
    
    func showError(_ error: UniversalLinkError) {
        let alert = UIAlertController(
            title: "Unable to Process Link",
            message: error.description,
            preferredStyle: .alert
        )
        
        switch error {
        case .tokenExpired:
            alert.addAction(UIAlertAction(title: "Request New Link", style: .default) { _ in
                // Navigate to forgot password screen
            })
        default:
            break
        }
        
        alert.addAction(UIAlertAction(title: "OK", style: .cancel))
        
        present(alert, animated: true)
    }
    
    func showLoading(_ show: Bool) {
        if show {
            let indicator = UIActivityIndicatorView(style: .large)
            indicator.center = view.center
            indicator.startAnimating()
            view.addSubview(indicator)
            loadingView = indicator
        } else {
            loadingView?.removeFromSuperview()
            loadingView = nil
        }
    }
}

class PasswordResetViewController: UIViewController {
    
    private let token: String
    private let email: String?
    
    private let newPasswordField = UITextField()
    private let confirmPasswordField = UITextField()
    private let resetButton = UIButton(type: .system)
    private let strengthLabel = UILabel()
    
    init(token: String, email: String?) {
        self.token = token
        self.email = email
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Reset Password"
        view.backgroundColor = .systemBackground
        setupUI()
    }
    
    private func setupUI() {
        let stackView = UIStackView()
        stackView.axis = .vertical
        stackView.spacing = 16
        stackView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(stackView)
        
        // Header
        let headerLabel = UILabel()
        headerLabel.text = "Create a New Password"
        headerLabel.font = .preferredFont(forTextStyle: .title2)
        headerLabel.textAlignment = .center
        stackView.addArrangedSubview(headerLabel)
        
        if let email = email {
            let emailLabel = UILabel()
            emailLabel.text = "For: \(email)"
            emailLabel.font = .preferredFont(forTextStyle: .subheadline)
            emailLabel.textColor = .secondaryLabel
            emailLabel.textAlignment = .center
            stackView.addArrangedSubview(emailLabel)
        }
        
        // New password field
        configureTextField(newPasswordField, placeholder: "New Password")
        newPasswordField.addTarget(self, action: #selector(passwordDidChange), for: .editingChanged)
        stackView.addArrangedSubview(newPasswordField)
        
        // Password strength indicator
        strengthLabel.font = .preferredFont(forTextStyle: .caption1)
        strengthLabel.textAlignment = .center
        stackView.addArrangedSubview(strengthLabel)
        
        // Confirm password field
        configureTextField(confirmPasswordField, placeholder: "Confirm Password")
        stackView.addArrangedSubview(confirmPasswordField)
        
        // Reset button
        resetButton.setTitle("Reset Password", for: .normal)
        resetButton.titleLabel?.font = .preferredFont(forTextStyle: .headline)
        resetButton.backgroundColor = .systemBlue
        resetButton.setTitleColor(.white, for: .normal)
        resetButton.layer.cornerRadius = 8
        resetButton.heightAnchor.constraint(equalToConstant: 50).isActive = true
        resetButton.addTarget(self, action: #selector(resetPasswordTapped), for: .touchUpInside)
        stackView.addArrangedSubview(resetButton)
        
        NSLayoutConstraint.activate([
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 24),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -24),
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -50)
        ])
    }
    
    private func configureTextField(_ textField: UITextField, placeholder: String) {
        textField.placeholder = placeholder
        textField.isSecureTextEntry = true
        textField.borderStyle = .roundedRect
        textField.textContentType = .newPassword
        textField.autocorrectionType = .no
        textField.autocapitalizationType = .none
        textField.heightAnchor.constraint(equalToConstant: 44).isActive = true
    }
    
    @objc private func passwordDidChange() {
        guard let password = newPasswordField.text else {
            strengthLabel.text = ""
            return
        }
        
        let strength = evaluatePasswordStrength(password)
        strengthLabel.text = strength.label
        strengthLabel.textColor = strength.color
    }
    
    @objc private func resetPasswordTapped() {
        guard let newPassword = newPasswordField.text,
              let confirmPassword = confirmPasswordField.text else {
            return
        }
        
        // Client-side validation
        guard !newPassword.isEmpty else {
            showAlert("Please enter a new password.")
            return
        }
        
        guard newPassword.count >= 8 else {
            showAlert("Password must be at least 8 characters long.")
            return
        }
        
        guard newPassword == confirmPassword else {
            showAlert("Passwords do not match.")
            return
        }
        
        let strength = evaluatePasswordStrength(newPassword)
        guard strength.meetsMinimum else {
            showAlert("Please choose a stronger password.")
            return
        }
        
        // Submit to server
        submitPasswordReset(token: token, newPassword: newPassword)
    }
    
    private func submitPasswordReset(token: String, newPassword: String) {
        resetButton.isEnabled = false
        
        guard let url = URL(string: "https://api.myapp.com/auth/reset-password") else { return }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.timeoutInterval = 15
        
        let body: [String: String] = [
            "token": token,
            "new_password": newPassword
        ]
        request.httpBody = try? JSONSerialization.data(withJSONObject: body)
        
        URLSession.shared.dataTask(with: request) { [weak self] data, response, error in
            DispatchQueue.main.async {
                self?.resetButton.isEnabled = true
                
                if let error = error {
                    self?.showAlert("Network error: \(error.localizedDescription)")
                    return
                }
                
                guard let httpResponse = response as? HTTPURLResponse else {
                    self?.showAlert("Unexpected server response.")
                    return
                }
                
                switch httpResponse.statusCode {
                case 200:
                    self?.showSuccessAndDismiss()
                case 410:
                    self?.showAlert("This reset link has expired. Please request a new one.")
                case 422:
                    self?.showAlert("Password does not meet requirements. Please try a different password.")
                default:
                    self?.showAlert("Something went wrong. Please try again.")
                }
            }
        }.resume()
    }
    
    private func showSuccessAndDismiss() {
        let alert = UIAlertController(
            title: "Password Reset Successful",
            message: "Your password has been updated. Please sign in with your new password.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Sign In", style: .default) { [weak self] _ in
            self?.navigationController?.popToRootViewController(animated: true)
        })
        present(alert, animated: true)
    }
    
    private func showAlert(_ message: String) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .cancel))
        present(alert, animated: true)
    }
    
    // MARK: - Password Strength
    
    private struct PasswordStrength {
        let label: String
        let color: UIColor
        let meetsMinimum: Bool
    }
    
    private func evaluatePasswordStrength(_ password: String) -> PasswordStrength {
        var score = 0
        
        if password.count >= 8 { score += 1 }
        if password.count >= 12 { score += 1 }
        if password.rangeOfCharacter(from: .uppercaseLetters) != nil { score += 1 }
        if password.rangeOfCharacter(from: .lowercaseLetters) != nil { score += 1 }
        if password.rangeOfCharacter(from: .decimalDigits) != nil { score += 1 }
        if password.rangeOfCharacter(from: CharacterSet.punctuationCharacters.union(.symbols)) != nil { score += 1 }
        
        switch score {
        case 0...2:
            return PasswordStrength(label: "Weak", color: .systemRed, meetsMinimum: false)
        case 3...4:
            return PasswordStrength(label: "Fair", color: .systemOrange, meetsMinimum: true)
        case 5:
            return PasswordStrength(label: "Strong", color: .systemGreen, meetsMinimum: true)
        default:
            return PasswordStrength(label: "Very Strong", color: .systemGreen, meetsMinimum: true)
        }
    }
}

// MARK: - Unit Test Support

#if DEBUG
extension UniversalLinkParser {
    /// Exposed for testing
    static func testParse(_ urlString: String) -> Result<ParsedUniversalLink, UniversalLinkError> {
        guard let url = URL(string: urlString) else {
            return .failure(.invalidURL)
        }
        return parse(url)
    }
}

// Example test cases
enum UniversalLinkTests {
    static func runAll() {
        testValidPasswordResetLink()
        testInvalidHost()
        testUnrecognizedPath()
        testMissingToken()
        testShortToken()
        testPathTraversalInToken()
        testHTTPSchemeRejected()
        testParameterPollution()
        print("✅ All universal link tests passed")
    }
    
    static func testValidPasswordResetLink() {
        let result = UniversalLinkParser.testParse("https://myapp.com/reset-password?token=abc123def456ghi789")
        switch result {
        case .success(let link):
            assert(link.destination == .passwordReset)
            assert(link.parameters["token"] == "abc123def456ghi789")
            assert(link.requiresAuth == false)
        case .failure(let error):
            fatalError("Expected success, got: \(error)")
        }
    }
    
    static func testInvalidHost() {
        let result = UniversalLinkParser.testParse("https://evil.com/reset-password?token=abc123def456ghi789")
        switch result {
        case .success:
            fatalError("Expected failure for untrusted host")
        case .failure(let error):
            if case .untrustedHost = error { } else {
                fatalError("Expected untrustedHost error, got: \(error)")
            }
        }
    }
    
    static func testUnrecognizedPath() {
        let result = UniversalLinkParser.testParse("https://myapp.com/admin/dashboard?token=abc123def456ghi789")
        switch result {
        case .success:
            fatalError("Expected failure for unrecognized path")
        case .failure(let error):
            if case .unrecognizedPath = error { } else {
                fatalError("Expected unrecognizedPath error, got: \(error)")
            }
        }
    }
    
    static func testMissingToken() {
        let result = UniversalLinkParser.testParse("https://myapp.com/reset-password")
        switch result {
        case .success:
            fatalError("Expected failure for missing token")
        case .failure(let error):
            if case .missingRequiredParameter = error { } else {
                fatalError("Expected missingRequiredParameter error, got: \(error)")
            }
        }
    }
    
    static func testShortToken() {
        let result = UniversalLinkParser.testParse("https://myapp.com/reset-password?token=abc")
        switch result {
        case .success:
            fatalError("Expected failure for short token")
        case .failure(let error):
            if case .invalidParameterFormat = error { } else {
                fatalError("Expected invalidParameterFormat error, got: \(error)")
            }
        }
    }
    
    static func testPathTraversalInToken() {
        let result = UniversalLinkParser.testParse("https://myapp.com/reset-password?token=../../etc/passwd1234567890")
        switch result {
        case .success:
            fatalError("Expected failure for path traversal token")
        case .failure(let error):
            if case .invalidParameterFormat = error { } else {
                fatalError("Expected invalidParameterFormat error, got: \(error)")
            }
        }
    }
    
    static func testHTTPSchemeRejected() {
        let result = UniversalLinkParser.testParse("http://myapp.com/reset-password?token=abc123def456ghi789")
        switch result {
        case .success:
            fatalError("Expected failure for HTTP scheme")
        case .failure(let error):
            if case .schemeNotAllowed = error { } else {
                fatalError("Expected schemeNotAllowed error, got: \(error)")
            }
        }
    }
    
    static func testParameterPollution() {
        // When duplicate parameters exist, only the first should be used
        let result = UniversalLinkParser.testParse("https://myapp.com/reset-password?token=abc123def456ghi789&token=malicious_token_12345")
        switch result {
        case .success(let link):
            assert(link.parameters["token"] == "abc123def456ghi789", "Should use first token value only")
        case .failure(let error):
            fatalError("Expected success, got: \(error)")
        }
    }
}
